159	  state,
160	  isValidationEnabled,
161	  dispatch,
162	}) => {
163	  const { t } = useCustomTranslation();
164	
165	  const [drPolicies, policyloaded, policyLoadError] =
166	    useK8sList<DRPolicyKind>(DRPolicyModel);
167	
168	  const [drPlacements, drpcLoaded, drpcLoadError] = useK8sWatchResource<
169	    DRPlacementControlKind[]
170	  >(getDRPlacementControlResourceObj());
