177	    'Select a DRCluster to choose your namespace.'
178	  );
179	  const noClusterHelperText = t('No DR cluster found');
180	
181	  const drClusters = getDRClusterFromPolicies(drPolicies);
182	
183	  const clusterNamevalidated = getValidatedProp(
184	    (isValidationEnabled && !clusterName) || !drClusters.length
185	  );
186	
187	  const setSelectedClusterName = (selectedClusterName: string) => {
188	    dispatch({
189	      type: EnrollDiscoveredApplicationStateType.SET_CLUSTER_NAME,
190	      payload: selectedClusterName,
191	    });
192	  };
193	
194	  return loaded && !loadError ? (
195	    <Form maxWidth="58rem">
196	      <FormSection title={t('Namespace selection')}>
197	        <Text component={TextVariants.small}>
198	          {t(
199	            'Enable disaster recovery protection by selecting the namespaces of your ACM discovered application.'
200	          )}
201	        </Text>
