210	            placeholderText={t('Select cluster')}
211	            selectedKey={clusterName}
212	            selectOptions={clusterOptions(drClusters)}
213	            onChange={setSelectedClusterName}
214	            validated={clusterNamevalidated}
215	            isDisabled={!drClusters.length}
216	          />
217	
218	          <FormHelperText>
219	            <HelperText>
220	              <HelperTextItem variant={clusterNamevalidated}>
221	                {!drClusters.length
222	                  ? noClusterHelperText
223	                  : clusterNameHelperText}
224	              </HelperTextItem>
225	            </HelperText>
226	          </FormHelperText>
227	        </FormGroup>
228	        <FormGroup
229	          label={t('Namespace')}
230	          fieldId="multi-namespace-selection"
231	          isRequired
232	        >
233	          <FormHelperText>
234	            <HelperText>
235	              <HelperTextItem variant="default">
236	                {t(
237	                  'Select namespaces that belongs to your ACM discovered applications.'
238	                )}
239	              </HelperTextItem>
240	            </HelperText>
241	          </FormHelperText>
242	          <Alert
243	            className="odf-alert pf-v6-u-mt-sm"
244	            title={t(
245	              'Once you select namespaces, applications regardless of their type, within those namespaces cannot be subsequently enrolled separately under disaster recovery protection.'
246	            )}
247	            variant={AlertVariant.info}
248	            isInline
249	          />
250	          <NamespaceSelectionTable
251	            namespaces={namespaces}
252	            clusterName={clusterName}
253	            policies={drPolicies}
254	            drPlacements={drPlacements}
255	            isValidationEnabled={isValidationEnabled}
256	            dispatch={dispatch}
257	          />
258	        </FormGroup>
259	        <NameInput
260	          name={name}
261	          drPlacements={drPlacements}
262	          dispatch={dispatch}
263	        />
264	      </FormSection>
265	    </Form>
266	  ) : (
267	    <StatusBox loaded={loaded} loadError={loadError} />
268	  );
269	};
270	
