272	  state: EnrollDiscoveredApplicationState;
273	  isValidationEnabled: boolean;
274	  dispatch: React.Dispatch<EnrollDiscoveredApplicationAction>;
275	};
276	
277	type NameInputProps = {
278	  name: string;
279	  drPlacements: DRPlacementControlKind[];
280	  dispatch: React.Dispatch<EnrollDiscoveredApplicationAction>;
281	};

